for photo_id in "${!IMAGES[@]}"; do
  url="${IMAGES[$photo_id]}"
  file="images/${photo_id}.jpg"
  if [ ! -f "$file" ]; then
    echo "Downloading $photo_id..."
    curl -s -L "$url" -o "$file" --max-time 30
    sleep 0.1
  fi
done

echo "All done! $(ls images/*.jpg 2>/dev/null | wc -l) images in images/"
